private TenantAdminDto.TenantView toView(Tenant t) {
    long credentials = credentialRepository.countByTenantId(t.getId());
    long apiKeys = apiKeyRepository.countActiveByTenantId(t.getId(), Instant.now());
    Instant lastEventAt = auditLogRepository
            .findFirstByTenantIdOrderByCreatedAtDesc(t.getId())
            .map(AuditLog::getCreatedAt)
            .orElse(null);
    return TenantAdminDto.TenantView.from(t, credentials, apiKeys, lastEventAt);
}

public static String hex(byte[] bytes) {
    StringBuilder s = new StringBuilder(bytes.length * 2);
    for (byte b : bytes) {
        s.append(String.format("%02x", b));
    }
    return s.toString();
}

private SigningKey generate() {
    try {
        KeyPairGenerator gen = KeyPairGenerator.getInstance("RSA");
        gen.initialize(2048);
        KeyPair pair = gen.generateKeyPair();

        RSAKey withoutKid = new RSAKey.Builder((RSAPublicKey) pair.getPublic())
                .privateKey((RSAPrivateKey) pair.getPrivate())
                .keyUse(KeyUse.SIGNATURE)
                .algorithm(JWSAlgorithm.RS256)
                .build();
        String kid = withoutKid.computeThumbprint().toString();
        RSAKey rsa = new RSAKey.Builder(withoutKid).keyID(kid).build();
        String publicJwk = rsa.toPublicJWK().toJSONString();
        byte[] sealed = envelope.seal(pair.getPrivate().getEncoded());
        return new SigningKey(kid, "RS256", publicJwk, sealed);
    } catch (Exception e) {
        throw new IllegalStateException("initial signing key generation failed", e);
    }
}

private SigningKey generateFreshActive() {
    try {
        KeyPairGenerator gen = KeyPairGenerator.getInstance("RSA");
        gen.initialize(2048);
        KeyPair pair = gen.generateKeyPair();
        RSAKey withoutKid = new RSAKey.Builder((RSAPublicKey) pair.getPublic())
                .privateKey((RSAPrivateKey) pair.getPrivate())
                .keyUse(KeyUse.SIGNATURE)
                .algorithm(JWSAlgorithm.RS256)
                .build();
        String kid = withoutKid.computeThumbprint().toString();
        RSAKey rsa = new RSAKey.Builder(withoutKid).keyID(kid).build();
        return new SigningKey(kid, "RS256", rsa.toPublicJWK().toJSONString(),
                envelope.seal(pair.getPrivate().getEncoded()));
    } catch (Exception e) {
        throw new IllegalStateException("rotation key generation failed", e);
    }
}

private void unauthorized(HttpServletResponse res) throws IOException {
    res.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
    res.setContentType("application/problem+json");
    res.getWriter().write(
            "{\"type\":\"about:blank\",\"status\":401,\"title\":\"Unauthorized\"}");
}

private void forbidden(HttpServletResponse res) throws IOException {
    res.setStatus(HttpServletResponse.SC_FORBIDDEN);
    res.setContentType("application/problem+json");
    res.getWriter().write(
            "{\"type\":\"about:blank\",\"status\":403,\"title\":\"Forbidden\",\"error\":\"insufficient_scope\"}");
}

private void tooManyRequests(HttpServletResponse res) throws IOException {
    res.setStatus(429);
    res.setHeader("Retry-After", "60");
    res.setContentType("application/problem+json");
    res.getWriter().write(
